return $input.all().map(item => {
  const original = item.json;

  const text = original.output || "";

  // Split by "* " and clean items
  const items = text
    .split("* ")
    .map(i => i.trim())
    .filter(i => i.length > 0);

  // Build proper HTML list
  const html =
    "<ul style='padding-left:20px; margin:0;'>" +
    items.map(i => `<li>${i}</li>`).join("") +
    "</ul>";

  // IMPORTANT: merge old data + new field
  return {
    json: {
      ...original,
      formattedOutput: html
    }
  };
});

return $input.all().map(item => {
  const original = item.json;

  const rawText = original.output || "";

  // Split on "* " bullet
  const items = rawText
    .split('* ')
    .map(i => i.trim())
    .filter(i => i.length > 0);

  // Convert to HTML list
  const listItems = items.map(i => `<li>${i}</li>`).join('');

  return {
    json: {
      ...original, // 👈 preserve email, product_name, etc.
      formattedOutput: `<ul style="padding-left:20px; margin:0;">${listItems}</ul>`
    }
  };
});
